  deadlineRow.className = 'project-detail__row';
  const deadlineLabel = document.createElement('strong');
  deadlineLabel.textContent = 'Deadline: ';
  const deadlineValue = document.createElement('span');
  deadlineValue.textContent = item.deadline !== undefined ? String(item.deadline) : '';
  deadlineRow.append(deadlineLabel, deadlineValue);

  const teamRow = document.createElement('div');
  teamRow.className = 'project-detail__row';
  const teamLabel = document.createElement('strong');
  teamLabel.textContent = 'Team: ';
  const teamValue = document.createElement('span');
  teamValue.textContent = item.team !== undefined ? String(item.team) : '';
  teamRow.append(teamLabel, teamValue);

  const statusRow = document.createElement('div');
